1	export type Item = { type: string; material?: string; enchantment?: number; cursed?: boolean };
2	
3	export type Step = { op: string; items?: Item[]; policy?: number; incident?: unknown };
4	
5	export type Scenario = {
6	  customer: { yearsWithMHPCO: number };
7	  steps: Step[];
8	};
9	
10	export type ScenarioResult = {
11	  results: StepResult[];
12	};
13	
14	const PROCESSING_FEE = 5;
15	
16	const BASE_PREMIUMS: Record<string, number> = {
17	  sword: 100,
18	  amulet: 60,
19	  staff: 80,
20	  potion: 40,
21	  rune: 25,
22	  moonstone: 25,
23	};
24	
25	type StepResult = { premium?: number; payout?: number; remainingCap?: number };
26	
27	const RUNE_BLOCK_SIZE = 3;
28	const RUNE_BLOCK_PREMIUM = 60;
29	
30	const basePremiumFor = (item: Item): number => BASE_PREMIUMS[item.type] ?? 0;
31	
32	const isThreeAlikeRuneBlock = (items: Item[]): boolean =>
33	  items.length === RUNE_BLOCK_SIZE && items.every((item) => item.type === "rune");
34	
35	const totalBasePremiumFor = (items: Item[]): number => {
36	  if (isThreeAlikeRuneBlock(items)) return RUNE_BLOCK_PREMIUM;
37	  return items.reduce((total, item) => total + basePremiumFor(item), 0);
38	};
39	
40	const quotePremium = (items: Item[]): number => totalBasePremiumFor(items) + PROCESSING_FEE;
41	
42	const processStep = ({ items = [] }: Step): StepResult => ({ premium: quotePremium(items) });
43	
44	export const runScenario = (scenario: Scenario): ScenarioResult => ({
45	  results: scenario.steps.map(processStep),
46	});
